# Allowlist of permitted origins for CORS
ALLOWED_ORIGINS = [
    'http://localhost:3000',
    'http://localhost:8080',
    'https://staging.example.com',
    'https://app.example.com'
]

# Maximum allowed values for pagination
MAX_PAGE_SIZE = 100
DEFAULT_PAGE_SIZE = 20

def validate_user_id(user_id: Optional[str]) -> bool:
    """Validate user ID format - alphanumeric and hyphens only, max 36 chars (UUID format)"""
    if not user_id:
        return False
    if len(user_id) > 36:
        return False
    return bool(re.match(r'^[a-zA-Z0-9\-]+$', user_id))

def validate_pagination_params(page: Optional[str], page_size: Optional[str]) -> tuple:
    """Validate and sanitize pagination parameters"""
    try:
        page_num = int(page) if page else 1
        size = int(page_size) if page_size else DEFAULT_PAGE_SIZE
        
        if page_num < 1:
            page_num = 1
        if size < 1 or size > MAX_PAGE_SIZE:
            size = DEFAULT_PAGE_SIZE
            
        return page_num, size
    except (ValueError, TypeError):
        return 1, DEFAULT_PAGE_SIZE

def get_cors_headers(origin: Optional[str]) -> Dict[str, str]:
    """Return CORS headers only for allowlisted origins"""
    headers = {
        'Content-Type': 'application/json',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains'
    }
    
    if origin and origin in ALLOWED_ORIGINS:
        headers['Access-Control-Allow-Origin'] = origin
        headers['Access-Control-Allow-Methods'] = 'GET, OPTIONS'
        headers['Access-Control-Allow-Headers'] = 'Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token'
        headers['Access-Control-Max-Age'] = '3600'
    
    return headers

